#define D 64
#define F 3072
#define V 50257
#define NM 50000
#define Z 131071
float*W,*wte,*wpe;int tk[1024],nt,bt[256];char ts[V][32];int tl[V],th[Z],tn[Z],mh[Z],mn[Z],ml[NM],mr[NM];
unsigned char rb[V][32];int rl[V];
unsigned hf(const char*s,int n){unsigned h=5381;for(int i=0;i<n;i++)h=h*33+(unsigned char)s[i];return h%Z;}
void ti(int i){unsigned h=hf(ts[i],tl[i]);tn[i]=th[h];th[h]=i;}
int tf(const char*s,int n){unsigned h=hf(s,n);for(int i=th[h];i>=0;i=tn[i])if(tl[i]==n&&!memcmp(ts[i],s,n))return i;return-1;}
unsigned mhash(int l,int r){return((unsigned)l*V+r)%Z;}
int mf(int l,int r){unsigned h=mhash(l,r);for(int i=mh[h];i>=0;i=mn[i])if(ml[i]==l&&mr[i]==r)return i;return-1;}
void mi(int i){unsigned h=mhash(ml[i],mr[i]);mn[i]=mh[h];mh[h]=i;}
void lb(char*p){
memset(th,-1,sizeof(th));memset(mh,-1,sizeof(mh));unsigned s[256];int n=0;
for(int i=0;i<256;i++)if((i>=33&&i<=126)||(i>=161&&i<=172)||(i>=174&&i<=255))s[i]=i;else s[i]=256+n++;
for(int b=0;b<256;b++){int q=0;for(int j=0;j<256;j++)if(s[j]<s[b])q++;bt[b]=q;}
for(int b=0;b<256;b++){int t=bt[b];unsigned c=s[b];rb[t][0]=b;rl[t]=1;
if(c<128){ts[t][0]=c;tl[t]=1;}else if(c<2048){ts[t][0]=0xC0|(c>>6);ts[t][1]=0x80|(c&63);tl[t]=2;}
else{ts[t][0]=0xE0|(c>>12);ts[t][1]=0x80|((c>>6)&63);ts[t][2]=0x80|(c&63);tl[t]=3;}ti(t);}
FILE*f=fopen(p,"r");char ln[256];fgets(ln,256,f);int x=0;
while(fgets(ln,256,f)&&x<NM){int l=strlen(ln);if(ln[l-1]=='\n')ln[--l]=0;int sp=-1;
for(int i=0;i<l;i++)if(ln[i]==' '){sp=i;break;}if(sp<0)continue;
int li=tf(ln,sp),ri=tf(ln+sp+1,l-sp-1);if(li<0||ri<0)continue;
ml[x]=li;mr[x]=ri;int a=tl[li];memcpy(ts[256+x],ts[li],a);
memcpy(ts[256+x]+a,ts[ri],tl[ri]);tl[256+x]=a+tl[ri];
memcpy(rb[256+x],rb[li],rl[li]);memcpy(rb[256+x]+rl[li],rb[ri],rl[ri]);
rl[256+x]=rl[li]+rl[ri];ti(256+x);mi(x);x++;}fclose(f);}
int tokenize(char*t,int*o){int n=strlen(t);for(int i=0;i<n;i++)o[i]=bt[(unsigned char)t[i]];
while(1){int bs=NM,bp=-1;for(int i=0;i<n-1;i++){int r=mf(o[i],o[i+1]);if(r>=0&&r<bs){bs=r;bp=i;}}
if(bp<0)break;o[bp]=256+bs;memmove(o+bp+1,o+bp+2,(n-bp-2)*sizeof(int));n--;}return n;}
float sc[1024];
void Ln(float*x,float*g,float*b,float*o,int T){for(int t=0;t<T;t++){float m=0,v=0;
for(int i=0;i<C;i++)m+=x[t*C+i];m/=C;
for(int i=0;i<C;i++)v+=(x[t*C+i]-m)*(x[t*C+i]-m);v=sqrtf(v/C+1e-5f);
for(int i=0;i<C;i++)o[t*C+i]=(x[t*C+i]-m)/v*g[i]+b[i];}}
float G(float x){return.5f*x*(1+tanhf(.7978845608f*(x+.044715f*x*x*x)));}
int main(int argc,char**argv){
FILE*f=fopen(argv[1],"rb");fseek(f,0,SEEK_END);long sz=ftell(f);fseek(f,0,SEEK_SET);
W=malloc(sz);fread(W,1,sz,f);fclose(f);
wte=W;wpe=wte+V*C;float*P=wpe+1024*C;
lb(argv[2]);nt=tokenize(argv[3],tk);
float*x=calloc(1024*C,sizeof(float)),*xn=malloc(1024*C*sizeof(float)),
*qk=malloc(1024*3*C*sizeof(float)),*ao=malloc(1024*C*sizeof(float)),
*ff=malloc(1024*F*sizeof(float));
int T=nt;
for(int t=0;t<T;t++)for(int i=0;i<C;i++)x[t*C+i]=wte[tk[t]*C+i]+wpe[t*C+i];
float*p=P;
for(int l=0;l<12;l++){
Ln(x,p,p+C,xn,T);p+=2*C;
for(int t=0;t<T;t++)for(int j=0;j<3*C;j++){float s=p[C*3*C+j];
for(int i=0;i<C;i++)s+=xn[t*C+i]*p[i*3*C+j];qk[t*3*C+j]=s;}p+=C*3*C+3*C;
for(int h=0;h<H;h++)for(int t=0;t<T;t++){
for(int s=0;s<=t;s++){float d=0;for(int i=0;i<D;i++)d+=qk[t*3*C+h*D+i]*qk[s*3*C+C+h*D+i];sc[s]=d/sqrtf(D);}
float mx=-1e30f;for(int s=0;s<=t;s++)if(sc[s]>mx)mx=sc[s];
float ss=0;for(int s=0;s<=t;s++){sc[s]=expf(sc[s]-mx);ss+=sc[s];}
for(int s=0;s<=t;s++)sc[s]/=ss;
for(int i=0;i<D;i++){float v=0;for(int s=0;s<=t;s++)v+=sc[s]*qk[s*3*C+2*C+h*D+i];ao[t*C+h*D+i]=v;}}
for(int t=0;t<T;t++)for(int j=0;j<C;j++){float s=p[C*C+j];
for(int i=0;i<C;i++)s+=ao[t*C+i]*p[i*C+j];x[t*C+j]+=s;}p+=C*C+C;
Ln(x,p,p+C,xn,T);p+=2*C;
for(int t=0;t<T;t++)for(int j=0;j<F;j++){float s=p[C*F+j];
for(int i=0;i<C;i++)s+=xn[t*C+i]*p[i*F+j];
ff[t*F+j]=G(s);}p+=C*F+F;
for(int t=0;t<T;t++)for(int j=0;j<C;j++){float s=p[F*C+j];
for(int i=0;i<F;i++)s+=ff[t*F+i]*p[i*C+j];x[t*C+j]+=s;}p+=F*C+C;}
Ln(x,p,p+C,xn,T);
float lo[V];int lt=T-1;
for(int j=0;j<V;j++){float s=0;for(int i=0;i<C;i++)s+=xn[lt*C+i]*wte[j*C+i];lo[j]=s;}
int best=0;float bv=-1e30f;
for(int j=1;j<V;j++)if(lo[j]>bv){bv=lo[j];best=j;}
printf("Best token: %d, logit: %f\n",best,bv);
for(int i=0;i<nt;i++)fwrite(rb[tk[i]],1,rl[tk[i]],stdout);
printf("[");fwrite(rb[best],1,rl[best],stdout);printf("]\n");
/* Also dump wte norm and xn norm */
float sn=0;for(int i=0;i<C;i++)sn+=xn[lt*C+i]*xn[lt*C+i];printf("xn norm: %f\n",sqrtf(sn));
float wn=0;for(int i=0;i<C;i++)wn+=wte[best*C+i]*wte[best*C+i];printf("wte[best] norm: %f\n",sqrtf(wn));
return 0;}
